        String estadosInicStr = estadosIniciales.isEmpty() ? "в€…" : "{" + String.join(",", estadosIniciales) + "}";
        sb.append("Оґ*(").append(estadosInicStr).append(", Оµ) = ").append(estadosInicStr).append("\n");

